def start_farming(self, icon, item):
    if self.process and self.process.poll() is None:
        return

    cmd = [sys.executable, SCRIPT_PATH, "--headless"] # Default hidden
    self.process = subprocess.Popen(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, cwd=os.getcwd(), creationflags=subprocess.CREATE_NO_WINDOW)
    self.update_menu_status("Running ", True)

    # Notify
    self.icon.notify("Farming Started in Background ", "Microsoft Rewards Farmer")

