def stop_farming(self, icon, item):
    if self.process:
        self.process.terminate()
        self.process = None

    # Kill all related
    subprocess.run("taskkill /F /IM python.exe /IM msedgedriver.exe /IM msedge.exe", shell=True, stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)

    self.update_menu_status("Stopped ", False)
    self.icon.notify("Farming Stopped ", "Microsoft Rewards Farmer")

