def refresh_profiles(self):
    """Refresh profile list from Edge browser."""
    # Clear existing checkboxes
    for widget in self.profile_frame.winfo_children():
        widget.destroy()
    self.profile_vars.clear()
    self.profile_paths = {}  # Store profile folder -> path mapping

    # Get Edge profiles
    edge_profiles = get_edge_profiles()

    if not edge_profiles:
        ttk.Label(self.profile_frame, text="(Không tìm thấy Edge profiles)").pack()
    else:
        for i, profile in enumerate(edge_profiles[:MAX_PROFILES]):
            var = tk.BooleanVar(value=True)
            display_text = f"{profile['name']} ({profile['folder']})"
            self.profile_vars[profile['folder']] = var
            self.profile_paths[profile['folder']] = profile['path']
            cb = ttk.Checkbutton(self.profile_frame, text=display_text, variable=var, style='TCheckbutton')
            cb.grid(row=i//3, column=i%3, sticky='w', padx=10, pady=2)

    self.log(f"Found {len(edge_profiles)} Edge profiles")

