def apply_mobile_emulation(driver, device_name=None):
    try:
        if device_name is None:
            device_name = random.choice(list(MOBILE_DEVICES.keys()))
        device = MOBILE_DEVICES.get(device_name, MOBILE_DEVICES['pixel_7'])

        # Get actual Edge version for UA
        try:
            from .driver import get_edge_version
            edge_ver = get_edge_version()
        except:
            edge_ver = "133.0.0.0"

        ua = device['ua'].replace('{VERSION}', edge_ver)

        driver.execute_cdp_cmd('Emulation.setDeviceMetricsOverride', {
            'width': device['width'], 'height': device['height'],
            'deviceScaleFactor': device['deviceScaleFactor'], 'mobile': device['mobile'],
            'screenWidth': device['screenWidth'], 'screenHeight': device['screenHeight']
        })
        driver.execute_cdp_cmd('Emulation.setTouchEmulationEnabled', {'enabled': True, 'maxTouchPoints': 5})
        driver.execute_cdp_cmd('Emulation.setUserAgentOverride', {
            'userAgent': ua,
            'platform': 'Android' if 'Android' in ua else 'iPhone'
        })

        driver.set_window_size(device['width'], device['height'])

        logging.info(f"   [MOBILE CDP] Emulating: {device_name} ({device['width']}x{device['height']}) Edge/{edge_ver}")
        return True
    except Exception as e:
        logging.warning(f"Mobile emulation failed: {e}")
        return False

def perform_mobile_news_reads(driver, count=10):
    """Đọc báo trên Mobile (Bing News)"""
    logging.info(f"--- [MOBILE READ] Bắt đầu đọc {count} bài báo ---")
    try:
        driver.get("https://www.bing.com/news")
        random_sleep(3, 5)

        selectors = ["a.title", ".news-card a", "a.news_title", ".b_algo a"]
        articles = []
        for sel in selectors:
            try:
                found = driver.find_elements(By.CSS_SELECTOR, sel)
                if found:
                    articles.extend(found)
            except: pass

        valid_links = []
        seen_urls = set()
        for a in articles:
            try:
                href = a.get_attribute("href")
                if href and "bing.com/news" not in href and href not in seen_urls:
                    valid_links.append(href)
                    seen_urls.add(href)
            except: pass

        logging.info(f"--- [MOBILE READ] Tìm thấy {len(valid_links)} bài báo hợp lệ ---")

        read_count = 0
        for i, link in enumerate(valid_links):
            if read_count >= count:
                break

            logging.info(f"[MOBILE READ {read_count+1}/{count}] Đang đọc: {link[:50]}...")
            try:
                driver.get(link)
                random_sleep(3, 5)
                driver.execute_script("window.scrollTo(0, document.body.scrollHeight/2);")
                random_sleep(2, 4)
                driver.execute_script("window.scrollTo(0, document.body.scrollHeight);")
                random_sleep(2, 4)
                read_count += 1
            except Exception as e:
                logging.error(f"Lỗi khi đọc báo: {e}")

        logging.info(f"--- [MOBILE READ] Hoàn thành {read_count}/{count} bài ---")

    except Exception as e:
        logging.error(f"Lỗi Mobile News: {e}")

