    """Get points from the Bing search page (inline check)."""
    # Try NEW UI first: #id_rh_w contains points in a span
    try:
        elm = driver.find_element(By.CSS_SELECTOR, "#id_rh_w span")
        txt = elm.text.replace(",", "").replace(".", "")
        if txt.isdigit():
            return int(txt)
    except:
        pass

    # Try OLD UI: #id_rc
    try:
        elm = driver.find_element(By.ID, "id_rc")
        txt = elm.text.replace(",", "").replace(".", "")
        if txt.isdigit():
            return int(txt)
    except:
        pass

    # Try aria-label approach for new UI
    try:
        elm = driver.find_element(By.CSS_SELECTOR, "a[aria-label='Microsoft Rewards'] span")
        txt = elm.text.replace(",", "").replace(".", "")
        if txt.isdigit():
            return int(txt)
    except:
        pass

    return None

def load_history():
    """Load points history from JSON file."""
    try:
        if os.path.exists(HISTORY_FILE):
            with open(HISTORY_FILE, 'r', encoding='utf-8') as f:
                return json.load(f)
    except:
        pass
    return {"records": []}

def save_history(data):
    """Save points history to JSON file."""
    try:
        with open(HISTORY_FILE, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2, ensure_ascii=False)
    except Exception as e:
        print(f"Error saving history: {e}")

def get_today_stats():
    """Get today's stats grouped by profile."""
    data = load_history()
    today = datetime.now().strftime("%Y-%m-%d")

    stats = {}
    for r in data.get("records", []):
        if r.get("date") == today:
            profile = r.get("profile", "Unknown")
            if profile not in stats:
                stats[profile] = {"earned": 0, "sessions": 0, "last_points": 0}
            stats[profile]["earned"] += r.get("earned", 0)
            stats[profile]["sessions"] += 1
            if isinstance(r.get("after"), int):
                stats[profile]["last_points"] = r["after"]

    return stats

def get_weekly_total():
    """Get total points earned in last 7 days."""
    data = load_history()
    week_ago = (datetime.now() - timedelta(days=7)).strftime("%Y-%m-%d")

    total = 0
    for r in data.get("records", []):
        if r.get("date", "") >= week_ago:
            total += r.get("earned", 0)
    return total

def get_daily_totals(days=14):
    """Get daily totals for last N days."""
    data = load_history()

    daily = {}
    for i in range(days):
        d = (datetime.now() - timedelta(days=i)).strftime("%Y-%m-%d")
        daily[d] = 0

    for r in data.get("records", []):
        date = r.get("date", "")
        if date in daily:
            daily[date] += r.get("earned", 0)

    # Return ordered list
    return [(d, daily[d]) for d in sorted(daily.keys())]

def was_farmed_today(profile_name):
    """Check if a profile has already been farmed today (earned > 0)."""
    data = load_history()
    today = datetime.now().strftime("%Y-%m-%d")
    for r in data.get("records", []):
        if r.get("date") == today and r.get("profile") == profile_name:
            if r.get("earned", 0) > 0:
                return True
    return False

def get_profile_summary():
    """Get summary stats for each profile ever farmed."""
    data = load_history()
    summary = {}
    for r in data.get("records", []):
        profile = r.get("profile", "Unknown")
        if profile not in summary:
            summary[profile] = {"total_earned": 0, "sessions": 0, "last_date": "", "last_points": 0}
        summary[profile]["total_earned"] += r.get("earned", 0)
        summary[profile]["sessions"] += 1
        if r.get("date", "") >= summary[profile]["last_date"]:
            summary[profile]["last_date"] = r.get("date", "")
            if isinstance(r.get("after"), int):
                summary[profile]["last_points"] = r["after"]
    return summary

def get_streak_days():
    """Get number of consecutive days with farming activity."""
    data = load_history()
    dates_with_earnings = set()
    for r in data.get("records", []):
        if r.get("earned", 0) > 0:
            dates_with_earnings.add(r.get("date", ""))

    if not dates_with_earnings:
        return 0

    streak = 0
    check_date = datetime.now()
    for _ in range(365):
        date_str = check_date.strftime("%Y-%m-%d")
        if date_str in dates_with_earnings:
            streak += 1
            check_date -= timedelta(days=1)
        else:
            break
    return streak

def _install_driver_with_retry():
    """Retry wrapper cho EdgeChromiumDriverManager"""
    from webdriver_manager.microsoft import EdgeChromiumDriverManager
    last_error = None
    for attempt in range(DRIVER_RETRY_ATTEMPTS):
        try:
            logging.info(f"Đang tải EdgeDriver (lần {attempt + 1}/{DRIVER_RETRY_ATTEMPTS})...")
            return EdgeChromiumDriverManager().install()
        except Exception as e:
            last_error = e
            logging.warning(f"Lần {attempt + 1} thất bại: {e}")
            if attempt < DRIVER_RETRY_ATTEMPTS - 1:
                time.sleep(DRIVER_RETRY_DELAY)
    raise last_error

@contextmanager
def get_driver(profile_path, is_mobile=False, headless=True):
    """Context manager để đảm bảo driver.quit()"""
    driver = setup_driver(profile_path, is_mobile, headless)
    try:
        yield driver
    finally:
        if driver:
            try:
                driver.quit()
                logging.info("Driver đã được đóng sạch.")
            except Exception as e:
                logging.warning(f"Lỗi khi đóng driver: {e}")

def is_driver_alive(driver):
    """Kiểm tra driver còn sống không"""
    try:
        driver.current_url
        return True
    except:
        return False

def safe_driver_quit(driver):
    """Đóng driver an toàn"""
    if driver:
        try:
            driver.quit()
        except:
            pass

def cleanup_clone_profiles():
    """Remove temporary cloned profile files."""
    temp_dir = tempfile.gettempdir()
    try:
        count = 0
        for item in os.listdir(temp_dir):
            if item.startswith("MSR_Clone_") or item == "MSRewards_Clone": # including old ones
                clone_path = os.path.join(temp_dir, item)
                if os.path.isdir(clone_path):
                    shutil.rmtree(clone_path, ignore_errors=True)
                    count += 1
        if count > 0:
            logging.info(f"[CLEANUP] Removed {count} temp clone folder(s).")
    except Exception as e:
        logging.warning(f"[CLEANUP] Failed to remove temp files: {e}")

def _is_new_ui(driver):
    """Detect if the dashboard is using the new accordion-based UI."""
    # New UI has accordion buttons with aria-labels like "Daily set", "Your activity"
    new_ui_indicators = [
        "button[aria-label='Daily set']",
        "button[aria-label='Your activity']",
        "button[aria-label='Achievements']",
    ]
    for selector in new_ui_indicators:
        try:
            elements = driver.find_elements(By.CSS_SELECTOR, selector)
            if elements:
                logging.info("[ACTIVITIES] Phát hiện UI MỚI (accordion-based)")
                return True
        except:
            pass

    # Also check for "See more tasks" text which is unique to new UI
    try:
        elements = driver.find_elements(By.XPATH, "//*[contains(text(), 'See more tasks')]")
        if elements:
            logging.info("[ACTIVITIES] Phát hiện UI MỚI (See more tasks)")
            return True
    except:
        pass

    logging.info("[ACTIVITIES] Sử dụng UI CŨ (mee-rewards)")
    return False

def _expand_new_ui_sections(driver):
    """Expand all accordion sections in the new UI."""
    # Try multiple possible section names (UI changes labels over time)
    sections = [
        "Daily set", "Your activity", "Achievements",
        "Your progress", "More activities", "More promotions",
    ]
    expanded = 0

    for section_name in sections:
        try:
            btn = driver.find_element(By.CSS_SELECTOR, f"button[aria-label='{section_name}']")
            # Check if already expanded
            is_expanded = btn.get_attribute("aria-expanded")
            if is_expanded == "false" or is_expanded is None:
                driver.execute_script("arguments[0].scrollIntoView({behavior: 'smooth', block: 'center'});", btn)
                time.sleep(0.5)
                driver.execute_script("arguments[0].click();", btn)
                time.sleep(random.uniform(1, 2))
                expanded += 1
                logging.info(f"   [NEW UI] Expanded: {section_name}")
        except:
            pass

    # Fallback: find ALL buttons with aria-expanded="false" and expand them
    if expanded == 0:
        try:
            buttons = driver.find_elements(By.CSS_SELECTOR, "button[aria-expanded='false']")
            for btn in buttons:
                try:
                    label = btn.get_attribute("aria-label") or btn.text
                    driver.execute_script("arguments[0].scrollIntoView({behavior: 'smooth', block: 'center'});", btn)
                    time.sleep(0.5)
                    driver.execute_script("arguments[0].click();", btn)
                    time.sleep(random.uniform(1, 2))
                    expanded += 1
                    logging.info(f"   [NEW UI] Expanded (fallback): {label}")
                except:
                    pass
        except:
            pass

    # Also click "See more tasks" if visible
    try:
        see_more = driver.find_elements(By.XPATH, "//*[contains(text(), 'See more tasks')]")
        for btn in see_more:
            if btn.is_displayed():
                driver.execute_script("arguments[0].click();", btn)
                time.sleep(1)
                logging.info("   [NEW UI] Clicked 'See more tasks'")
                break
    except:
        pass

    return expanded

def _get_new_ui_task_cards(driver):
    """Get all task cards from the new UI after expanding sections."""
    cards = []
    seen_texts = set()

    # Progress button keywords — these are NOT task cards, they open modals
    progress_keywords = ["search:", "activity:", "check-in:", "how to activate", "check in:"]
    # X/X completion pattern (e.g. "3/3", "7/7")
    import re as _re
    _xofx_pat = _re.compile(r'(\d+)/(\d+)')

    def _is_progress_complete(text: str) -> bool:
        """Check if progress text shows X/X = fully completed."""
        for num, denom in _xofx_pat.findall(text):
            if num == denom and int(num) > 0:
                return True
        return False

    def _is_progress_card(el):
        """Check if element is a progress tracking button (not a clickable task)."""
        try:
            tag = el.tag_name.lower()
            text = (el.text or "").lower()
            # <button> elements with progress keywords are trackers, not tasks
            if tag == 'button' and any(kw in text for kw in progress_keywords):
                return True
            # <div> streak cards showing X/X (already completed) — skip them
            if tag == 'div' and _is_progress_complete(text):
                return True
        except:
            pass
        return False


    # Primary: Find elements with 'CardRewards' in class name
    # Actual DOM class: "mai:rounded-cornerCardRewards"
    # This matches both <a> task cards AND <button> progress cards, so filter
    try:
        elements = driver.find_elements(By.CSS_SELECTOR, "[class*='CardRewards']")
        for el in elements:
            if _is_progress_card(el):
                continue
            text = (el.text or "").strip()[:60]
            if text and text not in seen_texts:
                seen_texts.add(text)
                cards.append(el)
                logging.info(f"   [CARDS] Found: <{el.tag_name}> {text[:40]}")
    except:
        pass

    # Secondary: Find cards by looking inside Daily set section specifically
    if not cards:
        try:
            daily_btn = driver.find_element(By.CSS_SELECTOR, "button[aria-label='Daily set']")
            # Navigate up to section container
            container = daily_btn.find_element(By.XPATH, "./..")
            children = container.find_elements(By.CSS_SELECTOR, "a[href]")
            for child in children:
                text = (child.text or "").strip()[:60]
                href = child.get_attribute("href") or ""
                if text and text not in seen_texts and "dashboard" not in href:
                    seen_texts.add(text)
                    cards.append(child)
        except:
            pass

    # Tertiary fallback: find ANY <a> or <div> containing point values (NOT buttons)
    if not cards:
        try:
            point_xpath = "//*[contains(text(), '+10') or contains(text(), '+5') or contains(text(), '+30')]"
            all_elements = driver.find_elements(By.XPATH, point_xpath)
            for el in all_elements:
                tag = el.tag_name.lower()
                if tag in ('a', 'div'):  # Exclude <button> — those are progress cards
                    text = (el.text or "").strip()[:60]
                    if text and len(text) > 5 and text not in seen_texts:
                        seen_texts.add(text)
                        cards.append(el)
        except:
            pass

    logging.info(f"[CARDS] Total task cards found: {len(cards)}")
    return cards

